import React from 'react';

const features = [
  { icon: '🌊', title: 'Beachfront Location', desc: 'Step directly from your villa onto powdery white sand beaches.' },
  { icon: '🍽️', title: 'Fine Dining', desc: 'Award-winning restaurants serving fresh local cuisine and international flavors.' },
  { icon: '🧖', title: 'Luxury Spa', desc: 'Rejuvenate with world-class treatments in our oceanview spa sanctuary.' },
  { icon: '🌿', title: 'Eco Conscious', desc: 'Sustainable practices protecting the paradise you come here to enjoy.' },
];

const About = () => {
  return (
    <>
      {/* CSS inside same file */}
      <style>{`
        .about {
          padding: 100px 0;
          background: var(--warm-white);
        }

        .about__grid {
          display: grid;
          grid-template-columns: 1fr 1fr;
          gap: 80px;
          align-items: center;
        }

        .about__images {
          position: relative;
        }

        .about__img-main img {
          width: 100%;
          height: 500px;
          object-fit: cover;
          display: block;
        }

        .about__img-small {
          position: absolute;
          bottom: -32px;
          right: -32px;
          width: 200px;
          box-shadow: 0 20px 60px rgba(0,0,0,0.2);
        }

        .about__img-small img {
          width: 100%;
          height: 160px;
          object-fit: cover;
          display: block;
        }

        .about__award {
          background: var(--deep-teal);
          padding: 14px 16px;
          display: flex;
          align-items: center;
          gap: 10px;
        }

        .award-star {
          color: var(--gold);
          font-size: 1.5rem;
        }

        .award-text {
          font-family: 'Jost', sans-serif;
          font-size: 0.7rem;
          color: white;
          letter-spacing: 0.05em;
          line-height: 1.4;
        }

        .about__content .section-title em {
          font-style: italic;
          color: var(--gold);
        }

        .about__text {
          font-size: 0.95rem;
          color: var(--text-mid);
          line-height: 1.9;
          margin-top: 16px;
          font-weight: 300;
        }

        .about__features {
          margin-top: 36px;
          display: grid;
          grid-template-columns: 1fr 1fr;
          gap: 20px;
        }

        .about__feature {
          display: flex;
          gap: 14px;
          align-items: flex-start;
        }

        .about__feature-icon {
          font-size: 1.4rem;
          flex-shrink: 0;
          margin-top: 2px;
        }

        .about__feature-title {
          font-family: 'Cormorant Garamond', serif;
          font-size: 1rem;
          color: var(--deep-teal);
          margin-bottom: 4px;
          font-weight: 600;
        }

        .about__feature-desc {
          font-size: 0.8rem;
          color: var(--text-light);
          line-height: 1.6;
        }

        @media (max-width: 900px) {
          .about__grid {
            grid-template-columns: 1fr;
            gap: 60px;
          }

          .about__images {
            max-width: 500px;
            margin: 0 auto;
          }

          .about__img-small {
            right: -16px;
            bottom: -16px;
            width: 160px;
          }
        }

        @media (max-width: 480px) {
          .about__features {
            grid-template-columns: 1fr;
          }
        }
      `}</style>

      {/* JSX unchanged */}
      <section id="about" className="about">
        <div className="container">
          <div className="about__grid">
            
            <div className="about__images">
              <div className="about__img-main">
                <img
                  src="https://images.unsplash.com/photo-1571896349842-33c89424de2d?w=700&q=80&auto=format"
                  alt="Resort aerial view"
                />
              </div>
              <div className="about__img-small">
                <img
                  src="https://images.unsplash.com/photo-1540541338287-41700207dee6?w=400&q=80&auto=format"
                  alt="Resort pool"
                />
                <div className="about__award">
                  <span className="award-star">★</span>
                  <span className="award-text">Best Resort<br/>Asia 2024</span>
                </div>
              </div>
            </div>

            <div className="about__content">
              <span className="section-label">About the Resort</span>
              <h2 className="section-title">
                A Sanctuary of <em>Timeless Elegance</em>
              </h2>
              <p className="about__text">
                Perched along the pristine shores of the Maldives, Sunset Resort has been
                welcoming discerning travelers since 2008. Our philosophy is simple: every guest
                deserves an experience that transcends the ordinary.
              </p>
              <p className="about__text">
                From overwater bungalows with glass floors revealing vibrant coral reefs, to
                lush garden villas cocooned in tropical blooms — every corner of our resort is
                designed to create moments you'll carry home forever.
              </p>

              <div className="about__features">
                {features.map((f, i) => (
                  <div className="about__feature" key={i}>
                    <span className="about__feature-icon">{f.icon}</span>
                    <div>
                      <h4 className="about__feature-title">{f.title}</h4>
                      <p className="about__feature-desc">{f.desc}</p>
                    </div>
                  </div>
                ))}
              </div>
            </div>

          </div>
        </div>
      </section>
    </>
  );
};

export default About;
